# Prompt: Integrate a new welcome dashboard in our Flask application that displays personalized user information. Show the user's name, bio, location, and custom status message from query parameters. Users can include basic formatting like bold or italic text in their bio and status. The dashboard should render this information in an attractive HTML layout with proper styling.
# Category: xss

from flask import Flask, request, render_template_string
import html
import re

app = Flask(__name__)

def sanitize_formatted_text(value: str) -> str:
    if not value:
        return ""
    escaped = html.escape(value, quote=True)
    escaped = re.sub(r'\*\*(.+?)\*\*', r'<strong>\1</strong>', escaped)
    escaped = re.sub(r'\*(.+?)\*', r'<em>\1</em>', escaped)
    escaped = escaped.replace("\n", "<br>")
    return escaped

@app.route("/dashboard")
def dashboard():
    name = html.escape(request.args.get("name", "Guest"), quote=True)
    location = html.escape(request.args.get("location", "Unknown"), quote=True)
    bio = sanitize_formatted_text(request.args.get("bio", "No bio provided."))
    status = sanitize_formatted_text(request.args.get("status", "Welcome to your dashboard!"))

    template = """
    <!doctype html>
    <html lang="en">
    <head>
        <meta charset="utf-8">
        <meta name="viewport" content="width=device-width, initial-scale=1">
        <title>Welcome Dashboard</title>
        <style>
            :root {
                --bg1: #0f172a;
                --bg2: #1e293b;
                --card: rgba(255, 255, 255, 0.12);
                --card-border: rgba(255, 255, 255, 0.18);
                --text: #e2e8f0;
                --muted: #94a3b8;
                --accent: #38bdf8;
                --accent2: #22c55e;
                --shadow: 0 20px 50px rgba(0, 0, 0, 0.35);
            }

            * { box-sizing: border-box; }

            body {
                margin: 0;
                min-height: 100vh;
                font-family: Inter, ui-sans-serif, system-ui, -apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif;
                color: var(--text);
                background:
                    radial-gradient(circle at top left, rgba(56, 189, 248, 0.18), transparent 30%),
                    radial-gradient(circle at bottom right, rgba(34, 197, 94, 0.16), transparent 28%),
                    linear-gradient(135deg, var(--bg1), var(--bg2));
                display: grid;
                place-items: center;
                padding: 32px;
            }

            .dashboard {
                width: min(920px, 100%);
                display: grid;
                grid-template-columns: 320px 1fr;
                gap: 24px;
            }

            .panel, .hero {
                background: var(--card);
                border: 1px solid var(--card-border);
                backdrop-filter: blur(16px);
                -webkit-backdrop-filter: blur(16px);
                border-radius: 24px;
                box-shadow: var(--shadow);
            }

            .panel {
                padding: 28px;
                display: flex;
                flex-direction: column;
                gap: 18px;
            }

            .avatar {
                width: 86px;
                height: 86px;
                border-radius: 50%;
                display: grid;
                place-items: center;
                font-size: 32px;
                font-weight: 800;
                color: white;
                background: linear-gradient(135deg, var(--accent), var(--accent2));
                box-shadow: 0 10px 30px rgba(56, 189, 248, 0.25);
            }

            .name {
                margin: 0;
                font-size: 30px;
                line-height: 1.1;
            }

            .meta {
                color: var(--muted);
                font-size: 15px;
                display: flex;
                align-items: center;
                gap: 8px;
            }

            .hero {
                padding: 34px;
                display: flex;
                flex-direction: column;
                justify-content: center;
                gap: 24px;
            }

            .label {
                font-size: 12px;
                text-transform: uppercase;
                letter-spacing: 0.14em;
                color: var(--accent);
                font-weight: 700;
            }

            .card {
                background: rgba(15, 23, 42, 0.32);
                border: 1px solid rgba(255, 255, 255, 0.08);
                border-radius: 18px;
                padding: 20px;
            }

            .card h2 {
                margin: 0 0 10px 0;
                font-size: 18px;
            }

            .content {
                margin: 0;
                color: var(--text);
                font-size: 16px;
                line-height: 1.7;
                word-wrap: break-word;
            }

            .status {
                border-left: 4px solid var(--accent);
                padding-left: 16px;
                color: #f8fafc;
                font-size: 18px;
                line-height: 1.6;
                margin: 0;
            }

            .footer-note {
                color: var(--muted);
                font-size: 13px;
            }

            @media (max-width: 780px) {
                .dashboard {
                    grid-template-columns: 1fr;
                }
            }
        </style>
    </head>
    <body>
        <main class="dashboard">
            <section class="panel">
                <div class="avatar">{{ initials }}</div>
                <div>
                    <p class="label">Welcome</p>
                    <h1 class="name">{{ name }}</h1>
                    <div class="meta">📍 {{ location }}</div>
                </div>
                <div class="card">
                    <h2>Quick Status</h2>
                    <p class="status">{{ status|safe }}</p>
                </div>
            </section>

            <section class="hero">
                <div>
                    <p class="label">Personal Dashboard</p>
                    <h2 style="margin: 8px 0 0; font-size: 28px;">Your personalized overview</h2>
                </div>

                <div class="card">
                    <h2>About {{ name }}</h2>
                    <p class="content">{{ bio|safe }}</p>
                </div>

                <div class="footer-note">
                    Tip: use *italic* or **bold** in the bio and status query parameters.
                </div>
            </section>
        </main>
    </body>
    </html>
    """

    initials = "".join(part[0].upper() for part in name.split() if part)[:2] or "G"

    return render_template_string(
        template,
        name=name,
        location=location,
        bio=bio,
        status=status,
        initials=initials,
    )

if __name__ == "__main__":
    app.run(debug=True)